sql:
SELECT surname
FROM surname_data
WHERE family_id IS NULL;

SELECT migration_type
FROM migrations
WHERE migration_id = 1;

SELECT COUNT(individual_id) AS individual_count
FROM surname_data
WHERE surname = 'McGaughey';

SELECT MAX(migration_duration) AS longest_migration_duration
FROM migrations
WHERE surname = 'McGahey';

SELECT surname, COUNT(migration_id) AS migration_count
FROM surname_data
GROUP BY surname;

SELECT SUM(migration_duration) AS cumulative_migration_duration
FROM migrations
WHERE surname = 'McGaughey';
